#include<bits/stdc++.h>
using namespace std;
int main(void){
	int a[1001][1001]={0},n,b=0,maxn=0,flag=1;
	cin>>n;
	for(int i=0;i<n;i++){
		for(int j=0;j<n;j++){
			cin>>a[i][j];
		}
	}
	for(int i=0;i<n;i++){
		for(int j=0;j<n;j++){
			if(a[i][j]==0){
				flag=0;
				b=0;for(int k=0;k<n;k++)b+=a[i][k];
				for(int k=0;k<n;k++)b+=a[k][j];
			}
			maxn=max(b,maxn);
		}
	}
	if(flag){cout<<"Bad Game!";return false;}
	cout<<maxn;
	return false;
}
